// Parse ALL Bessemer portfolio companies (v2.6: dual dedup)
const html = $input.first().json.data || $input.first().json.content || '';

const results = [];
const vcName = 'Bessemer Venture Partners';
const seenSlugs = new Set();
const seenNames = new Set();

const companyPattern = /href=["']https?:\/\/(?:www\.)?bvp\.com\/companies\/([a-z0-9-]+)["'][^>]*>([^<]*)</gi;
let match;

while ((match = companyPattern.exec(html)) !== null) {
  const slug = match[1].trim().toLowerCase();
  let name = match[2].trim();

  if (!slug || slug.length < 2 || slug === 'companies' || slug === 'all') continue;

  if (seenSlugs.has(slug)) continue;
  seenSlugs.add(slug);

  if (!name || name.length < 2) {
    name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  }

  name = name.replace(/^\s*[-\u2022]\s*/, '').trim();
  if (!name || name.length < 2 || name.length > 60) continue;

  const normalizedName = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seenNames.has(normalizedName)) continue;
  seenNames.add(normalizedName);

  results.push({
    json: {
      company_name: name,
      company_url: 'https://www.bvp.com/companies/' + slug,
      description: name + ' - Bessemer Venture Partners portfolio company',
      source: vcName
    }
  });
}

console.log('Bessemer total unique companies:', results.length);
return results;

// Parse ALL Battery portfolio companies (v2.6: dual dedup)
const html = $input.first().json.data || $input.first().json.content || '';

const results = [];
const vcName = 'Battery Ventures';
const seenSlugs = new Set();
const seenNames = new Set();

const companyPattern = /href=["'](?:https?:\/\/(?:www\.)?battery\.com)?\/company\/([a-z0-9-]+)\/?["'][^>]*>/gi;
let match;

while ((match = companyPattern.exec(html)) !== null) {
  const slug = match[1].trim().toLowerCase();

  if (!slug || slug.length < 2 || slug === 'company' || slug === 'all') continue;

  if (seenSlugs.has(slug)) continue;
  seenSlugs.add(slug);

  let name = slug.split('-').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');
  name = name.replace(/\s+Inc$/i, '').replace(/\s+Ltd$/i, '').trim();
  name = name.replace(/ai$/i, 'AI').replace(/^ai\s/i, 'AI ');

  if (!name || name.length < 2 || name.length > 60) continue;

  const normalizedName = name.toLowerCase().replace(/[^a-z0-9]/g, '');
  if (seenNames.has(normalizedName)) continue;
  seenNames.add(normalizedName);

  results.push({
    json: {
      company_name: name,
      company_url: 'https://www.battery.com/company/' + slug + '/',
      description: name + ' - Battery Ventures portfolio company',
      source: vcName
    }
  });
}

console.log('Battery total unique companies:', results.length);
return results;
